olors.disabledBgColor;  themeConfig.button.error.hoverBackgroundColor = colors.hoverBgColor;  themeConfig.button.error.textColor = colors.textColor;  themeConfig.button.error.disabledTextColor = colors.disabledTextColor;  themeConfig.button.error.hoverTextColor = colors.hoverTextColor;  applyPreviewThemeToDOM(themeConfig);})watch(themeConfig, (newVal) => {  if (!newVal) {    return;  }  console.log("主题变化", newVal)  applyPreviewThemeToDOM(newVal);})onMounted(() => {  console.log("编辑器页面加载完成")});</script><template>  <div class="theme-editor">    <n-collapse>      <n-collapse-item title="全局颜色配置" name="1">        <div class="sectorization">          <div class="color-line">            <div class="color-label">主色调：</div>            <div class="color-select">              <n-color-picker modes="['rgba']" v-model:value="themeConfig.universal.primary"                              @click="forbidCalculate = false"                              placement="left-end"/>            </div>          </div>          <div class="color-line">            <div class="color-label">次色调：</div>            <div class="color-select">              <n-color-picker modes="['rgba']" v-model:value="themeConfig.universal.secondary"                              @click="forbidCalculate = false"                              :placement="'left-end'"/>            </div>          </div>          <div class="color-line">            <div class="color-label">背景色：</div>            <div class="color-select">              <n-color-picker modes="['rgba']" v-model:value="themeConfig.universal.background"                              @click="forbidCalculate = false"                              :placement="'left-end'"/>            </div>          </div>          <div class="color-line">            <div class="color-label">删除色：</div>            <div class="color-select">              <n-color-picker modes="['rgba']" v-model:value="themeConfig.universal.delete"     